66:     typedef struct packed {
67:         logic [6:0]  address;
68:         logic [31:0] data;
69:         logic [1:0]  op;
70:     } dmi_t;
71: 
72:     typedef enum logic [1:0] {
73:                                 DMINoError = 2'h0, DMIReservedError = 2'h1,
74:                                 DMIOPFailed = 2'h2, DMIBusy = 2'h3
75:                              } dmi_error_e;
76: 
77:     typedef enum logic [3:0] { Idle, Read, WaitReadValid, Write, WaitWriteValid, PassChk, PassChkWait, PassChkValid} state_e;
78:     state_e state_d, state_q;
79: 
80:     logic [$bits(dmi_t)-1:0] dr_d, dr_q;
81:     logic [6:0] address_d, address_q;
82:     logic [31:0] data_d, data_q;
83:     logic pass_check;
84:     logic pass_mode;
85:     logic startHash;
86:     logic [256-1:0] exp_hash, pass_hash;
87:     logic [512-1:0] pass_data;
88:     logic hmac_ready;
89:     logic hashValid;
90: 
91: 
92:     dmi_t  dmi;
93:     assign dmi          = dmi_t'(dr_q);
94:     assign dmi_req.addr = address_q;
95:     assign dmi_req.data = data_q;
96:     assign dmi_req.op   = (state_q == Write) ? dm::DTM_WRITE : dm::DTM_READ;
97:     // we'will always be ready to accept the data we requested
98:     assign dmi_resp_ready = 1'b1;
99: 
100:     logic error_dmi_busy;
101:     dmi_error_e error_d, error_q;
102: 
103:     assign jtag_unlock_o = pass_check;
104:     assign exp_hash = jtag_hash_i; 
105: 
106:     always_comb begin
107:         error_dmi_busy = 1'b0;
108:         // default assignments
109:         state_d   = state_q;
110:         address_d = address_q;
111:         data_d    = data_q;
112:         error_d   = error_q;
113: 
114:         dmi_req_valid = 1'b0;
115:         pass_check = 1'b0;
116:         pass_mode = 1'b0;
117: 
118:         case (state_q)
119:             Idle: begin
120:                 // make sure that no error is sticky
121:                 if (dmi_access && update_dr && (error_q == DMINoError)) begin
122:                     // save address and value
123:                     address_d = dmi.address;
124:                     data_d = dmi.data;
125:                     if ( (dm::dtm_op_e'(dmi.op) == dm::DTM_READ) && (pass_check | ~we_flag == 1) ) begin
126:                         state_d = Read;
127:                     end else if ( (dm::dtm_op_e'(dmi.op) == dm::DTM_WRITE) && (pass_check == 1) ) begin
128:                         state_d = Write;
129:                     end else if (dm::dtm_op_e'(dmi.op) == dm::DTM_PASS) begin
130:                         state_d = Write;
131:                         pass_mode = 1'b1;
132:                     end 
133:                     // else this is a nop and we can stay here
134:                 end
135:             end
136: 
137:             Read: begin
138:                 dmi_req_valid = 1'b1;
139:                 if (dmi_req_ready) begin
140:                     state_d = WaitReadValid;
141:                 end
142: 
143:             end
144: 
145:             WaitReadValid: begin
146:                 // load data into register and shift out
147:                 if (dmi_resp_valid) begin
148:                     state_d = Idle;
149:                 end
150:             end
151: 
152:             Write: begin
153:                 dmi_req_valid = 1'b1;
154:                 // got a valid answer go back to idle
155:                 if (dmi_req_ready) begin
156:                     data_d = dmi_resp.data; 
157:                     if (pass_mode) begin
158:                         pass_data = { {60{8'h00}}, data_d};
159:                         state_d = PassChk;
160:                         pass_mode = 1'b0;
161:                     end else begin
162:                         state_d = Idle;
163:                     end
164:                 end
165:             end
166: 
167:             WaitWriteValid: begin
168:                 // just wait for idle here
169:                 if (dmi_resp_valid) begin
170:                     state_d = Idle;
171:                 end
172:             end
173: 
174:             PassChk: begin
175:                 if(hmac_ready) begin
176:                     startHash = 1'b1;
177:                     state_d = PassChkWait;
178:                 end else begin
179:                     state_d = PassChk;
180:                 end
181:             end
182: 
183:             PassChkWait: begin
184:                 if(!hmac_ready) begin
185:                     startHash = 1'b0;
186:                     state_d = PassChkValid;
187:                 end else begin
188:                     state_d = PassChkWait;
189:                 end
190:             end
191: 
192:             PassChkValid: begin
193:                if(hashValid) begin 
194:                     if(exp_hash == pass_hash) begin 
195:                         pass_check = 1'b1;
196:                     end else begin
197:                         pass_check = 1'b0;
198:                     end
199:                     state_d = Idle;
200:                 end else begin
201:                    state_d = PassChkValid;
202:                 end  
203:             end
204:         endcase
205: 
206:         // update_dr means we got another request but we didn't finish
207:         // the one in progress, this state is sticky
208:         if (update_dr && state_q != Idle) begin
209:             error_dmi_busy = 1'b1;
210:         end
211: 
212:         // if capture_dr goes high while we are in the read state
213:         // or in the corresponding wait state we are not giving back a valid word
214:         // -> throw an error
215:         if (capture_dr && state_q inside {Read, WaitReadValid}) begin
216:             error_dmi_busy = 1'b1;
217:         end
218: 
219:         if (error_dmi_busy) begin
220:             error_d = DMIBusy;
221:         end
222:         // clear sticky error flag
223:         if (dmi_reset && dtmcs_select) begin
224:             error_d = DMINoError;
225:         end
226:     end
227: 
228:     // shift register
229:     assign dmi_tdo = dr_q[0];
230: 
231:     always_comb begin
232:         dr_d    = dr_q;
233: 
234:         if (capture_dr) begin
235:             if (dmi_access) begin
236:                 if (error_q == DMINoError && !error_dmi_busy) begin
237:                     dr_d = {address_q, data_q, DMINoError};
238:                 // DMI was busy, report an error
239:                 end else if (error_q == DMIBusy || error_dmi_busy) begin
240:                     dr_d = {address_q, data_q, DMIBusy};
241:                 end
242:             end
243:         end
244: 
245:         if (shift_dr) begin
246:             if (dmi_access) dr_d = {dmi_tdi, dr_q[$bits(dr_q)-1:1]};
247:         end
248: 
249:         if (test_logic_reset) begin
250:             dr_d = '0;
251:         end
252:     end
253: 
254:     always_ff @(posedge tck_i or negedge trst_ni) begin
255:         if (!trst_ni) begin
256:             dr_q      <= '0;
257:             state_q   <= Idle;
258:             address_q <= '0;
259:             data_q    <= '0;
260:             error_q   <= DMINoError;
261:         end else begin
262:             dr_q      <= dr_d;
263:             state_q   <= state_d;
264:             address_q <= address_d;
265:             data_q    <= data_d;
266:             error_q   <= error_d;
267:         end
268:     end
