74:                     sha_init = ~key_hash_bypass_i;
75:                     sha_h_block_update = key_hash_bypass_i; 
76:                     sha_new_msg = 1'b0;
77:                     state = HASHI_1_WAIT;
78:                 end else begin
79:                     state = HASHI_1;
80:                 end
81:             end
