106:                 end else begin
107:                     state = HASHI_3;
108:                 end
109:             end
110:             HASHI_3_WAIT: begin
111:                 state = HASHO_1;
112:                 sha_new_msg = 0; 
113:             end
114:             HASHO_1: begin
115:                 if (sha_digest_valid) begin
