121:                     sha_new_msg = 1'b0;
122:                     state = HASHO_1_WAIT;
123:                 end else begin
124:                     state = HASHO_1;
125:                 end
126:             end
127:             HASHO_1_WAIT: begin
128:                 state = HASHO_2;
129:                 sha_h_block_update = 0; 
130:                 sha_init = 0; 
131:             end
