135:                     sha_msg = {sha_idigest, 1'h1, 191'h0, 64'd768}; 
136:                     sha_new_msg = 1'b1; //tell SHA to start
137:                     state = HASHO_2_WAIT;
138:                 end else begin
139:                     state = HASHO_2;
140:                 end
141:             end
