107:                     state = HASHI_3;
108:                 end
109:             end
110:             HASHI_3_WAIT: begin
111:                 state = HASHO_1;
112:                 sha_new_msg = 0; 
113:             end
114:             HASHO_1: begin
115:                 if (sha_digest_valid) begin
116:                     sha_idigest = sha_digest; 
117:                     sha_msg = opad;
118:                     sha_h_block = okey_hash_i; 
